import { Effect, Supervisor, Fiber, Duration, pipe } from "effect";

const child = (label: string) =>
  pipe(Effect.succeed(label), Effect.delay(Duration.millis(5)));

const program = Effect.gen(function* () {
  const supervisor = yield* Supervisor.track;
  const work = Effect.gen(function* () {
    const a = yield* Effect.fork(child("a"));
    const b = yield* Effect.fork(child("b"));
    yield* Fiber.join(a);
    yield* Fiber.join(b);
    return "done" as const;
  });
  const observed = yield* Effect.supervised(work, supervisor);
  const snapshot = yield* supervisor.value;
  return { observed, count: snapshot.length };
});

export const run = program;
