import { Effect, Supervisor, Fiber, Duration, pipe } from "effect";

const unit = (i: number) =>
  pipe(Effect.succeed(i), Effect.delay(Duration.millis(1)));

export const program: Effect.Effect<number> = Effect.gen(function* () {
  const sup = yield* Supervisor.track;
  const work = Effect.gen(function* () {
    const fs = yield* Effect.forEach([1, 2, 3, 4], (i) => Effect.fork(unit(i)));
    yield* Effect.forEach(fs, Fiber.join);
  });
  yield* Effect.supervised(work, sup);
  const seen = yield* sup.value;
  return seen.length;
});
