import { Effect, Metric, MetricBoundaries, Duration, pipe } from "effect";

const h = Metric.histogram(
  "step_ms",
  MetricBoundaries.linear({ start: 0, width: 5, count: 6 }),
);

const step = (label: string) =>
  pipe(
    Effect.succeed(label),
    Effect.delay(Duration.millis(3)),
    Metric.trackDuration(h),
  );

export const program = Effect.gen(function* () {
  yield* step("x");
  yield* step("y");
  return yield* Metric.value(h);
});
